91	static char *
92	ngx_stream_block(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
93	{
94	    char                          *rv;
95	    ngx_uint_t                     mi, m, s;
96	    ngx_conf_t                     pcf;
97	    ngx_stream_module_t           *module;
98	    ngx_stream_conf_ctx_t         *ctx;
99	    ngx_stream_core_srv_conf_t   **cscfp;
100	    ngx_stream_core_main_conf_t   *cmcf;
101	
102	    if (*(ngx_stream_conf_ctx_t **) conf) {
103	        return "is duplicate";
104	    }
105	
106	    /* the main stream context */
107	
108	    ctx = ngx_pcalloc(cf->pool, sizeof(ngx_stream_conf_ctx_t));
109	    if (ctx == NULL) {
110	        return NGX_CONF_ERROR;
111	    }
112	
113	    *(ngx_stream_conf_ctx_t **) conf = ctx;
114	
115	    /* count the number of the stream modules and set up their indices */
116	
117	    ngx_stream_max_module = ngx_count_modules(cf->cycle, NGX_STREAM_MODULE);
118	
119	
120	    /* the stream main_conf context, it's the same in the all stream contexts */
121	
122	    ctx->main_conf = ngx_pcalloc(cf->pool,
123	                                 sizeof(void *) * ngx_stream_max_module);
124	    if (ctx->main_conf == NULL) {
125	        return NGX_CONF_ERROR;
126	    }
127	
128	
129	    /*
130	     * the stream null srv_conf context, it is used to merge
131	     * the server{}s' srv_conf's
132	     */
133	
134	    ctx->srv_conf = ngx_pcalloc(cf->pool,
135	                                sizeof(void *) * ngx_stream_max_module);
136	    if (ctx->srv_conf == NULL) {
137	        return NGX_CONF_ERROR;
138	    }
139	
140	
141	    /*
142	     * create the main_conf's and the null srv_conf's of the all stream modules
143	     */
144	
145	    for (m = 0; cf->cycle->modules[m]; m++) {
146	        if (cf->cycle->modules[m]->type != NGX_STREAM_MODULE) {
147	            continue;
148	        }
149	
150	        module = cf->cycle->modules[m]->ctx;
151	        mi = cf->cycle->modules[m]->ctx_index;
152	
153	        if (module->create_main_conf) {
154	            ctx->main_conf[mi] = module->create_main_conf(cf);
155	            if (ctx->main_conf[mi] == NULL) {
156	                return NGX_CONF_ERROR;
157	            }
158	        }
159	
160	        if (module->create_srv_conf) {
161	            ctx->srv_conf[mi] = module->create_srv_conf(cf);
162	            if (ctx->srv_conf[mi] == NULL) {
163	                return NGX_CONF_ERROR;
164	            }
165	        }
166	    }
167	
168	
169	    pcf = *cf;
170	    cf->ctx = ctx;
171	
172	    for (m = 0; cf->cycle->modules[m]; m++) {
173	        if (cf->cycle->modules[m]->type != NGX_STREAM_MODULE) {
174	            continue;
175	        }
176	
177	        module = cf->cycle->modules[m]->ctx;
178	
179	        if (module->preconfiguration) {
180	            if (module->preconfiguration(cf) != NGX_OK) {
181	                return NGX_CONF_ERROR;
182	            }
183	        }
184	    }
185	
186	
187	    /* parse inside the stream{} block */
188	
189	    cf->module_type = NGX_STREAM_MODULE;
190	    cf->cmd_type = NGX_STREAM_MAIN_CONF;
191	    rv = ngx_conf_parse(cf, NULL);
192	
193	    if (rv != NGX_CONF_OK) {
194	        *cf = pcf;
195	        return rv;
196	    }
197	
198	
199	    /* init stream{} main_conf's, merge the server{}s' srv_conf's */
200	
201	    cmcf = ctx->main_conf[ngx_stream_core_module.ctx_index];
202	    cscfp = cmcf->servers.elts;
203	
204	    for (m = 0; cf->cycle->modules[m]; m++) {
205	        if (cf->cycle->modules[m]->type != NGX_STREAM_MODULE) {
206	            continue;
207	        }
208	
209	        module = cf->cycle->modules[m]->ctx;
210	        mi = cf->cycle->modules[m]->ctx_index;
211	
212	        /* init stream{} main_conf's */
213	
214	        cf->ctx = ctx;
215	
216	        if (module->init_main_conf) {
217	            rv = module->init_main_conf(cf, ctx->main_conf[mi]);
218	            if (rv != NGX_CONF_OK) {
219	                *cf = pcf;
220	                return rv;
221	            }
222	        }
223	
224	        for (s = 0; s < cmcf->servers.nelts; s++) {
225	
226	            /* merge the server{}s' srv_conf's */
227	
228	            cf->ctx = cscfp[s]->ctx;
229	
230	            if (module->merge_srv_conf) {
231	                rv = module->merge_srv_conf(cf,
232	                                            ctx->srv_conf[mi],
233	                                            cscfp[s]->ctx->srv_conf[mi]);
234	                if (rv != NGX_CONF_OK) {
235	                    *cf = pcf;
236	                    return rv;
237	                }
238	            }
239	        }
240	    }
241	
242	    if (ngx_stream_init_phases(cf, cmcf) != NGX_OK) {
243	        return NGX_CONF_ERROR;
244	    }
245	
246	    for (m = 0; cf->cycle->modules[m]; m++) {
247	        if (cf->cycle->modules[m]->type != NGX_STREAM_MODULE) {
248	            continue;
249	        }
250	
251	        module = cf->cycle->modules[m]->ctx;
252	
253	        if (module->postconfiguration) {
254	            if (module->postconfiguration(cf) != NGX_OK) {
255	                return NGX_CONF_ERROR;
256	            }
257	        }
258	    }
259	
260	    if (ngx_stream_variables_init_vars(cf) != NGX_OK) {
261	        return NGX_CONF_ERROR;
262	    }
263	
264	    *cf = pcf;
265	
266	    if (ngx_stream_init_phase_handlers(cf, cmcf) != NGX_OK) {
267	        return NGX_CONF_ERROR;
268	    }
269	
270	    /* optimize the lists of ports, addresses and server names */
271	
272	    if (ngx_stream_optimize_servers(cf, cmcf, cmcf->ports) != NGX_OK) {
273	        return NGX_CONF_ERROR;
274	    }
275	
276	    return NGX_CONF_OK;
277	}
