280	static ngx_int_t
281	ngx_stream_init_phases(ngx_conf_t *cf, ngx_stream_core_main_conf_t *cmcf)
282	{
283	    if (ngx_array_init(&cmcf->phases[NGX_STREAM_POST_ACCEPT_PHASE].handlers,
284	                       cf->pool, 1, sizeof(ngx_stream_handler_pt))
285	        != NGX_OK)
286	    {
287	        return NGX_ERROR;
288	    }
289	
290	    if (ngx_array_init(&cmcf->phases[NGX_STREAM_PREACCESS_PHASE].handlers,
291	                       cf->pool, 1, sizeof(ngx_stream_handler_pt))
292	        != NGX_OK)
293	    {
294	        return NGX_ERROR;
295	    }
296	
297	    if (ngx_array_init(&cmcf->phases[NGX_STREAM_ACCESS_PHASE].handlers,
298	                       cf->pool, 1, sizeof(ngx_stream_handler_pt))
299	        != NGX_OK)
300	    {
301	        return NGX_ERROR;
302	    }
303	
304	    if (ngx_array_init(&cmcf->phases[NGX_STREAM_SSL_PHASE].handlers,
305	                       cf->pool, 1, sizeof(ngx_stream_handler_pt))
306	        != NGX_OK)
307	    {
308	        return NGX_ERROR;
309	    }
310	
311	    if (ngx_array_init(&cmcf->phases[NGX_STREAM_PREREAD_PHASE].handlers,
312	                       cf->pool, 1, sizeof(ngx_stream_handler_pt))
313	        != NGX_OK)
314	    {
315	        return NGX_ERROR;
316	    }
317	
318	    if (ngx_array_init(&cmcf->phases[NGX_STREAM_LOG_PHASE].handlers,
319	                       cf->pool, 1, sizeof(ngx_stream_handler_pt))
320	        != NGX_OK)
321	    {
322	        return NGX_ERROR;
323	    }
324	
325	    return NGX_OK;
326	}
