329	static ngx_int_t
330	ngx_stream_init_phase_handlers(ngx_conf_t *cf,
331	    ngx_stream_core_main_conf_t *cmcf)
332	{
333	    ngx_int_t                     j;
334	    ngx_uint_t                    i, n;
335	    ngx_stream_handler_pt        *h;
336	    ngx_stream_phase_handler_t   *ph;
337	    ngx_stream_phase_handler_pt   checker;
338	
339	    n = 1 /* content phase */;
340	
341	    for (i = 0; i < NGX_STREAM_LOG_PHASE; i++) {
342	        n += cmcf->phases[i].handlers.nelts;
343	    }
344	
345	    ph = ngx_pcalloc(cf->pool,
346	                     n * sizeof(ngx_stream_phase_handler_t) + sizeof(void *));
347	    if (ph == NULL) {
348	        return NGX_ERROR;
349	    }
350	
351	    cmcf->phase_engine.handlers = ph;
352	    n = 0;
353	
354	    for (i = 0; i < NGX_STREAM_LOG_PHASE; i++) {
355	        h = cmcf->phases[i].handlers.elts;
356	
357	        switch (i) {
358	
359	        case NGX_STREAM_PREREAD_PHASE:
360	            checker = ngx_stream_core_preread_phase;
361	            break;
362	
363	        case NGX_STREAM_CONTENT_PHASE:
364	            ph->checker = ngx_stream_core_content_phase;
365	            n++;
366	            ph++;
367	
368	            continue;
369	
370	        default:
371	            checker = ngx_stream_core_generic_phase;
372	        }
373	
374	        n += cmcf->phases[i].handlers.nelts;
375	
376	        for (j = cmcf->phases[i].handlers.nelts - 1; j >= 0; j--) {
377	            ph->checker = checker;
378	            ph->handler = h[j];
379	            ph->next = n;
380	            ph++;
381	        }
382	    }
383	
384	    return NGX_OK;
385	}
