388	ngx_int_t
389	ngx_stream_add_listen(ngx_conf_t *cf, ngx_stream_core_srv_conf_t *cscf,
390	    ngx_stream_listen_opt_t *lsopt)
391	{
392	    in_port_t                     p;
393	    ngx_uint_t                    i;
394	    struct sockaddr              *sa;
395	    ngx_stream_conf_port_t       *port;
396	    ngx_stream_core_main_conf_t  *cmcf;
397	
398	    cmcf = ngx_stream_conf_get_module_main_conf(cf, ngx_stream_core_module);
399	
400	    if (cmcf->ports == NULL) {
401	        cmcf->ports = ngx_array_create(cf->temp_pool, 2,
402	                                       sizeof(ngx_stream_conf_port_t));
403	        if (cmcf->ports == NULL) {
404	            return NGX_ERROR;
405	        }
406	    }
407	
408	    sa = lsopt->sockaddr;
409	    p = ngx_inet_get_port(sa);
410	
411	    port = cmcf->ports->elts;
412	    for (i = 0; i < cmcf->ports->nelts; i++) {
413	
414	        if (p != port[i].port
415	            || lsopt->type != port[i].type
416	            || sa->sa_family != port[i].family)
417	        {
418	            continue;
419	        }
420	
421	        /* a port is already in the port list */
422	
423	        return ngx_stream_add_addresses(cf, cscf, &port[i], lsopt);
424	    }
425	
426	    /* add a port to the port list */
427	
428	    port = ngx_array_push(cmcf->ports);
429	    if (port == NULL) {
430	        return NGX_ERROR;
431	    }
432	
433	    port->family = sa->sa_family;
434	    port->type = lsopt->type;
435	    port->port = p;
436	    port->addrs.elts = NULL;
437	
438	    return ngx_stream_add_address(cf, cscf, port, lsopt);
439	}
