442	static ngx_int_t
443	ngx_stream_add_addresses(ngx_conf_t *cf, ngx_stream_core_srv_conf_t *cscf,
444	    ngx_stream_conf_port_t *port, ngx_stream_listen_opt_t *lsopt)
445	{
446	    ngx_uint_t               i, default_server, proxy_protocol,
447	                             protocols, protocols_prev;
448	    ngx_stream_conf_addr_t  *addr;
449	#if (NGX_STREAM_SSL)
450	    ngx_uint_t               ssl;
451	#endif
452	
453	    /*
454	     * we cannot compare whole sockaddr struct's as kernel
455	     * may fill some fields in inherited sockaddr struct's
456	     */
457	
458	    addr = port->addrs.elts;
459	
460	    for (i = 0; i < port->addrs.nelts; i++) {
461	
462	        if (ngx_cmp_sockaddr(lsopt->sockaddr, lsopt->socklen,
463	                             addr[i].opt.sockaddr,
464	                             addr[i].opt.socklen, 0)
465	            != NGX_OK)
466	        {
467	            continue;
468	        }
469	
470	        /* the address is already in the address list */
471	
472	        if (ngx_stream_add_server(cf, cscf, &addr[i]) != NGX_OK) {
473	            return NGX_ERROR;
474	        }
475	
476	        /* preserve default_server bit during listen options overwriting */
477	        default_server = addr[i].opt.default_server;
478	
479	        proxy_protocol = lsopt->proxy_protocol || addr[i].opt.proxy_protocol;
480	        protocols = lsopt->proxy_protocol;
481	        protocols_prev = addr[i].opt.proxy_protocol;
482	
483	#if (NGX_STREAM_SSL)
484	        ssl = lsopt->ssl || addr[i].opt.ssl;
485	        protocols |= lsopt->ssl << 1;
486	        protocols_prev |= addr[i].opt.ssl << 1;
487	#endif
488	
489	        if (lsopt->set) {
490	
491	            if (addr[i].opt.set) {
492	                ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
493	                                   "duplicate listen options for %V",
494	                                   &addr[i].opt.addr_text);
495	                return NGX_ERROR;
496	            }
497	
498	            addr[i].opt = *lsopt;
499	        }
500	
501	        /* check the duplicate "default" server for this address:port */
502	
503	        if (lsopt->default_server) {
504	
505	            if (default_server) {
506	                ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
507	                                   "a duplicate default server for %V",
508	                                   &addr[i].opt.addr_text);
509	                return NGX_ERROR;
510	            }
511	
512	            default_server = 1;
513	            addr[i].default_server = cscf;
514	        }
515	
516	        /* check for conflicting protocol options */
517	
518	        if ((protocols | protocols_prev) != protocols_prev) {
519	
520	            /* options added */
521	
522	            if ((addr[i].opt.set && !lsopt->set)
523	                || addr[i].protocols_changed
524	                || (protocols | protocols_prev) != protocols)
525	            {
526	                ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
527	                                   "protocol options redefined for %V",
528	                                   &addr[i].opt.addr_text);
529	            }
530	
531	            addr[i].protocols = protocols_prev;
532	            addr[i].protocols_set = 1;
533	            addr[i].protocols_changed = 1;
534	
535	        } else if ((protocols_prev | protocols) != protocols) {
536	
537	            /* options removed */
538	
539	            if (lsopt->set
540	                || (addr[i].protocols_set && protocols != addr[i].protocols))
541	            {
542	                ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
543	                                   "protocol options redefined for %V",
544	                                   &addr[i].opt.addr_text);
545	            }
546	
547	            addr[i].protocols = protocols;
548	            addr[i].protocols_set = 1;
549	            addr[i].protocols_changed = 1;
550	
551	        } else {
552	
553	            /* the same options */
554	
555	            if ((lsopt->set && addr[i].protocols_changed)
556	                || (addr[i].protocols_set && protocols != addr[i].protocols))
557	            {
558	                ngx_conf_log_error(NGX_LOG_WARN, cf, 0,
559	                                   "protocol options redefined for %V",
560	                                   &addr[i].opt.addr_text);
561	            }
562	
563	            addr[i].protocols = protocols;
564	            addr[i].protocols_set = 1;
565	        }
566	
567	        addr[i].opt.default_server = default_server;
568	        addr[i].opt.proxy_protocol = proxy_protocol;
569	#if (NGX_STREAM_SSL)
570	        addr[i].opt.ssl = ssl;
571	#endif
572	
573	        return NGX_OK;
574	    }
575	
576	    /* add the address to the addresses list that bound to this port */
577	
578	    return ngx_stream_add_address(cf, cscf, port, lsopt);
579	}
