582	/*
583	 * add the server address, the server names and the server core module
584	 * configurations to the port list
585	 */
586	
587	static ngx_int_t
588	ngx_stream_add_address(ngx_conf_t *cf, ngx_stream_core_srv_conf_t *cscf,
589	    ngx_stream_conf_port_t *port, ngx_stream_listen_opt_t *lsopt)
590	{
591	    ngx_stream_conf_addr_t  *addr;
592	
593	    if (port->addrs.elts == NULL) {
594	        if (ngx_array_init(&port->addrs, cf->temp_pool, 4,
595	                           sizeof(ngx_stream_conf_addr_t))
596	            != NGX_OK)
597	        {
598	            return NGX_ERROR;
599	        }
600	    }
601	
602	    addr = ngx_array_push(&port->addrs);
603	    if (addr == NULL) {
604	        return NGX_ERROR;
605	    }
606	
607	    addr->opt = *lsopt;
608	    addr->protocols = 0;
609	    addr->protocols_set = 0;
610	    addr->protocols_changed = 0;
611	    addr->hash.buckets = NULL;
612	    addr->hash.size = 0;
613	    addr->wc_head = NULL;
614	    addr->wc_tail = NULL;
615	#if (NGX_PCRE)
616	    addr->nregex = 0;
617	    addr->regex = NULL;
618	#endif
619	    addr->default_server = cscf;
620	    addr->servers.elts = NULL;
621	
622	    return ngx_stream_add_server(cf, cscf, addr);
623	}
