626	/* add the server core module configuration to the address:port */
627	
628	static ngx_int_t
629	ngx_stream_add_server(ngx_conf_t *cf, ngx_stream_core_srv_conf_t *cscf,
630	    ngx_stream_conf_addr_t *addr)
631	{
632	    ngx_uint_t                    i;
633	    ngx_stream_core_srv_conf_t  **server;
634	
635	    if (addr->servers.elts == NULL) {
636	        if (ngx_array_init(&addr->servers, cf->temp_pool, 4,
637	                           sizeof(ngx_stream_core_srv_conf_t *))
638	            != NGX_OK)
639	        {
640	            return NGX_ERROR;
641	        }
642	
643	    } else {
644	        server = addr->servers.elts;
645	        for (i = 0; i < addr->servers.nelts; i++) {
646	            if (server[i] == cscf) {
647	                ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
648	                                   "a duplicate listen %V",
649	                                   &addr->opt.addr_text);
650	                return NGX_ERROR;
651	            }
652	        }
653	    }
654	
655	    server = ngx_array_push(&addr->servers);
656	    if (server == NULL) {
657	        return NGX_ERROR;
658	    }
659	
660	    *server = cscf;
661	
662	    return NGX_OK;
663	}
664	
665	
666	static ngx_int_t
667	ngx_stream_optimize_servers(ngx_conf_t *cf, ngx_stream_core_main_conf_t *cmcf,
668	    ngx_array_t *ports)
669	{
670	    ngx_uint_t               p, a;
671	    ngx_stream_conf_port_t  *port;
672	    ngx_stream_conf_addr_t  *addr;
673	
674	    if (ports == NULL) {
675	        return NGX_OK;
676	    }
677	
678	    port = ports->elts;
679	    for (p = 0; p < ports->nelts; p++) {
680	
681	        ngx_sort(port[p].addrs.elts, (size_t) port[p].addrs.nelts,
682	                 sizeof(ngx_stream_conf_addr_t), ngx_stream_cmp_conf_addrs);
683	
684	        /*
685	         * check whether all name-based servers have the same
686	         * configuration as a default server for given address:port
687	         */
688	
689	        addr = port[p].addrs.elts;
690	        for (a = 0; a < port[p].addrs.nelts; a++) {
691	
692	            if (addr[a].servers.nelts > 1
693	#if (NGX_PCRE)
694	                || addr[a].default_server->captures
695	#endif
696	               )
697	            {
698	                if (ngx_stream_server_names(cf, cmcf, &addr[a]) != NGX_OK) {
699	                    return NGX_ERROR;
700	                }
701	            }
702	        }
703	
704	        if (ngx_stream_init_listening(cf, &port[p]) != NGX_OK) {
705	            return NGX_ERROR;
706	        }
707	    }
708	
709	    return NGX_OK;
710	}
711	
712	
713	static ngx_int_t
714	ngx_stream_server_names(ngx_conf_t *cf, ngx_stream_core_main_conf_t *cmcf,
715	    ngx_stream_conf_addr_t *addr)
716	{
717	    ngx_int_t                     rc;
718	    ngx_uint_t                    n, s;
719	    ngx_hash_init_t               hash;
720	    ngx_hash_keys_arrays_t        ha;
721	    ngx_stream_server_name_t     *name;
722	    ngx_stream_core_srv_conf_t  **cscfp;
723	#if (NGX_PCRE)
724	    ngx_uint_t                    regex, i;
725	
726	    regex = 0;
727	#endif
728	
729	    ngx_memzero(&ha, sizeof(ngx_hash_keys_arrays_t));
730	
731	    ha.temp_pool = ngx_create_pool(NGX_DEFAULT_POOL_SIZE, cf->log);
732	    if (ha.temp_pool == NULL) {
733	        return NGX_ERROR;
734	    }
735	
736	    ha.pool = cf->pool;
737	
738	    if (ngx_hash_keys_array_init(&ha, NGX_HASH_LARGE) != NGX_OK) {
739	        goto failed;
740	    }
741	
742	    cscfp = addr->servers.elts;
743	
744	    for (s = 0; s < addr->servers.nelts; s++) {
745	
746	        name = cscfp[s]->server_names.elts;
747	
748	        for (n = 0; n < cscfp[s]->server_names.nelts; n++) {
749	
750	#if (NGX_PCRE)
751	            if (name[n].regex) {
752	                regex++;
753	                continue;
754	            }
755	#endif
756	
757	            rc = ngx_hash_add_key(&ha, &name[n].name, name[n].server,
758	                                  NGX_HASH_WILDCARD_KEY);
759	
760	            if (rc == NGX_ERROR) {
761	                goto failed;
762	            }
763	
764	            if (rc == NGX_DECLINED) {
765	                ngx_log_error(NGX_LOG_EMERG, cf->log, 0,
766	                              "invalid server name or wildcard \"%V\" on %V",
767	                              &name[n].name, &addr->opt.addr_text);
768	                goto failed;
769	            }
770	
771	            if (rc == NGX_BUSY) {
772	                ngx_log_error(NGX_LOG_WARN, cf->log, 0,
773	                              "conflicting server name \"%V\" on %V, ignored",
774	                              &name[n].name, &addr->opt.addr_text);
775	            }
776	        }
777	    }
778	
779	    hash.key = ngx_hash_key_lc;
780	    hash.max_size = cmcf->server_names_hash_max_size;
781	    hash.bucket_size = cmcf->server_names_hash_bucket_size;
782	    hash.name = "server_names_hash";
783	    hash.pool = cf->pool;
784	
785	    if (ha.keys.nelts) {
786	        hash.hash = &addr->hash;
787	        hash.temp_pool = NULL;
788	
789	        if (ngx_hash_init(&hash, ha.keys.elts, ha.keys.nelts) != NGX_OK) {
790	            goto failed;
791	        }
792	    }
793	
794	    if (ha.dns_wc_head.nelts) {
795	
796	        ngx_qsort(ha.dns_wc_head.elts, (size_t) ha.dns_wc_head.nelts,
797	                  sizeof(ngx_hash_key_t), ngx_stream_cmp_dns_wildcards);
798	
799	        hash.hash = NULL;
800	        hash.temp_pool = ha.temp_pool;
801	
802	        if (ngx_hash_wildcard_init(&hash, ha.dns_wc_head.elts,
803	                                   ha.dns_wc_head.nelts)
804	            != NGX_OK)
805	        {
806	            goto failed;
807	        }
808	
809	        addr->wc_head = (ngx_hash_wildcard_t *) hash.hash;
810	    }
811	
812	    if (ha.dns_wc_tail.nelts) {
813	
814	        ngx_qsort(ha.dns_wc_tail.elts, (size_t) ha.dns_wc_tail.nelts,
815	                  sizeof(ngx_hash_key_t), ngx_stream_cmp_dns_wildcards);
816	
817	        hash.hash = NULL;
818	        hash.temp_pool = ha.temp_pool;
819	
820	        if (ngx_hash_wildcard_init(&hash, ha.dns_wc_tail.elts,
821	                                   ha.dns_wc_tail.nelts)
822	            != NGX_OK)
823	        {
824	            goto failed;
825	        }
826	
827	        addr->wc_tail = (ngx_hash_wildcard_t *) hash.hash;
828	    }
829	
830	    ngx_destroy_pool(ha.temp_pool);
831	
832	#if (NGX_PCRE)
833	
834	    if (regex == 0) {
835	        return NGX_OK;
836	    }
837	
838	    addr->nregex = regex;
839	    addr->regex = ngx_palloc(cf->pool,
840	                             regex * sizeof(ngx_stream_server_name_t));
841	    if (addr->regex == NULL) {
842	        return NGX_ERROR;
843	    }
844	
845	    i = 0;
846	
847	    for (s = 0; s < addr->servers.nelts; s++) {
848	
849	        name = cscfp[s]->server_names.elts;
850	
851	        for (n = 0; n < cscfp[s]->server_names.nelts; n++) {
852	            if (name[n].regex) {
853	                addr->regex[i++] = name[n];
854	            }
855	        }
856	    }
857	
858	#endif
859	
860	    return NGX_OK;
861	
862	failed:
863	
864	    ngx_destroy_pool(ha.temp_pool);
865	
866	    return NGX_ERROR;
867	}
868	
869	
870	static ngx_int_t
871	ngx_stream_cmp_conf_addrs(const void *one, const void *two)
872	{
873	    ngx_stream_conf_addr_t  *first, *second;
874	
875	    first = (ngx_stream_conf_addr_t *) one;
876	    second = (ngx_stream_conf_addr_t *) two;
877	
878	    if (first->opt.wildcard) {
879	        /* a wildcard address must be the last resort, shift it to the end */
880	        return 1;
881	    }
882	
883	    if (second->opt.wildcard) {
884	        /* a wildcard address must be the last resort, shift it to the end */
885	        return -1;
886	    }
887	
888	    if (first->opt.bind && !second->opt.bind) {
889	        /* shift explicit bind()ed addresses to the start */
890	        return -1;
891	    }
892	
893	    if (!first->opt.bind && second->opt.bind) {
894	        /* shift explicit bind()ed addresses to the start */
895	        return 1;
896	    }
897	
898	    /* do not sort by default */
899	
900	    return 0;
901	}
902	
903	
904	static int ngx_libc_cdecl
905	ngx_stream_cmp_dns_wildcards(const void *one, const void *two)
906	{
907	    ngx_hash_key_t  *first, *second;
908	
909	    first = (ngx_hash_key_t *) one;
910	    second = (ngx_hash_key_t *) two;
911	
912	    return ngx_dns_strcmp(first->key.data, second->key.data);
913	}
