915	
916	static ngx_int_t
917	ngx_stream_init_listening(ngx_conf_t *cf, ngx_stream_conf_port_t *port)
918	{
919	    ngx_uint_t               i, last, bind_wildcard;
920	    ngx_listening_t         *ls;
921	    ngx_stream_port_t       *stport;
922	    ngx_stream_conf_addr_t  *addr;
923	
924	    addr = port->addrs.elts;
925	    last = port->addrs.nelts;
926	
927	    /*
928	     * If there is a binding to an "*:port" then we need to bind() to
929	     * the "*:port" only and ignore other implicit bindings.  The bindings
930	     * have been already sorted: explicit bindings are on the start, then
931	     * implicit bindings go, and wildcard binding is in the end.
932	     */
933	
934	    if (addr[last - 1].opt.wildcard) {
935	        addr[last - 1].opt.bind = 1;
936	        bind_wildcard = 1;
937	
938	    } else {
939	        bind_wildcard = 0;
940	    }
941	
942	    i = 0;
943	
944	    while (i < last) {
945	
946	        if (bind_wildcard && !addr[i].opt.bind) {
947	            i++;
948	            continue;
949	        }
950	
951	        ls = ngx_stream_add_listening(cf, &addr[i]);
952	        if (ls == NULL) {
953	            return NGX_ERROR;
954	        }
955	
956	        stport = ngx_pcalloc(cf->pool, sizeof(ngx_stream_port_t));
957	        if (stport == NULL) {
958	            return NGX_ERROR;
959	        }
960	
961	        ls->servers = stport;
962	
963	        stport->naddrs = i + 1;
964	
965	        switch (ls->sockaddr->sa_family) {
966	
967	#if (NGX_HAVE_INET6)
968	        case AF_INET6:
969	            if (ngx_stream_add_addrs6(cf, stport, addr) != NGX_OK) {
970	                return NGX_ERROR;
971	            }
972	            break;
973	#endif
974	        default: /* AF_INET */
975	            if (ngx_stream_add_addrs(cf, stport, addr) != NGX_OK) {
976	                return NGX_ERROR;
977	            }
978	            break;
979	        }
980	
981	        addr++;
982	        last--;
983	    }
984	
985	    return NGX_OK;
986	}
987	
988	
989	static ngx_listening_t *
990	ngx_stream_add_listening(ngx_conf_t *cf, ngx_stream_conf_addr_t *addr)
991	{
992	    ngx_listening_t             *ls;
993	    ngx_stream_core_srv_conf_t  *cscf;
994	
995	    ls = ngx_create_listening(cf, addr->opt.sockaddr, addr->opt.socklen);
996	    if (ls == NULL) {
997	        return NULL;
998	    }
999	
1000	    ls->addr_ntop = 1;
1001	
1002	    ls->handler = ngx_stream_init_connection;
1003	
1004	    ls->pool_size = 256;
1005	
1006	    cscf = addr->default_server;
1007	
1008	    ls->logp = cscf->error_log;
1009	    ls->log.data = &ls->addr_text;
1010	    ls->log.handler = ngx_accept_log_error;
1011	
1012	    ls->type = addr->opt.type;
1013	    ls->protocol = addr->opt.protocol;
1014	    ls->backlog = addr->opt.backlog;
1015	    ls->rcvbuf = addr->opt.rcvbuf;
1016	    ls->sndbuf = addr->opt.sndbuf;
1017	
1018	    ls->keepalive = addr->opt.so_keepalive;
1019	#if (NGX_HAVE_KEEPALIVE_TUNABLE)
1020	    ls->keepidle = addr->opt.tcp_keepidle;
1021	    ls->keepintvl = addr->opt.tcp_keepintvl;
1022	    ls->keepcnt = addr->opt.tcp_keepcnt;
1023	#endif
1024	
1025	#if (NGX_HAVE_DEFERRED_ACCEPT && defined SO_ACCEPTFILTER)
1026	    ls->accept_filter = addr->opt.accept_filter;
1027	#endif
1028	
1029	#if (NGX_HAVE_DEFERRED_ACCEPT && defined TCP_DEFER_ACCEPT)
1030	    ls->deferred_accept = addr->opt.deferred_accept;
1031	#endif
1032	
1033	#if (NGX_HAVE_INET6)
1034	    ls->ipv6only = addr->opt.ipv6only;
1035	#endif
1036	
1037	#if (NGX_HAVE_SETFIB)
1038	    ls->setfib = addr->opt.setfib;
1039	#endif
1040	
1041	#if (NGX_HAVE_TCP_FASTOPEN)
1042	    ls->fastopen = addr->opt.fastopen;
1043	#endif
1044	
1045	#if (NGX_HAVE_REUSEPORT)
1046	    ls->reuseport = addr->opt.reuseport;
1047	#endif
1048	
1049	    ls->wildcard = addr->opt.wildcard;
1050	
1051	    return ls;
1052	}
1053	
1054	
1055	static ngx_int_t
1056	ngx_stream_add_addrs(ngx_conf_t *cf, ngx_stream_port_t *stport,
1057	    ngx_stream_conf_addr_t *addr)
1058	{
1059	    ngx_uint_t                   i;
1060	    struct sockaddr_in          *sin;
1061	    ngx_stream_in_addr_t        *addrs;
1062	    ngx_stream_virtual_names_t  *vn;
1063	
1064	    stport->addrs = ngx_pcalloc(cf->pool,
1065	                                stport->naddrs * sizeof(ngx_stream_in_addr_t));
1066	    if (stport->addrs == NULL) {
1067	        return NGX_ERROR;
1068	    }
1069	
1070	    addrs = stport->addrs;
1071	
1072	    for (i = 0; i < stport->naddrs; i++) {
1073	
1074	        sin = (struct sockaddr_in *) addr[i].opt.sockaddr;
1075	        addrs[i].addr = sin->sin_addr.s_addr;
1076	        addrs[i].conf.default_server = addr[i].default_server;
1077	#if (NGX_STREAM_SSL)
1078	        addrs[i].conf.ssl = addr[i].opt.ssl;
1079	#endif
1080	        addrs[i].conf.proxy_protocol = addr[i].opt.proxy_protocol;
1081	
1082	        if (addr[i].hash.buckets == NULL
1083	            && (addr[i].wc_head == NULL
1084	                || addr[i].wc_head->hash.buckets == NULL)
1085	            && (addr[i].wc_tail == NULL
1086	                || addr[i].wc_tail->hash.buckets == NULL)
1087	#if (NGX_PCRE)
1088	            && addr[i].nregex == 0
1089	#endif
1090	            )
1091	        {
1092	            continue;
1093	        }
1094	
1095	        vn = ngx_palloc(cf->pool, sizeof(ngx_stream_virtual_names_t));
1096	        if (vn == NULL) {
1097	            return NGX_ERROR;
1098	        }
1099	
1100	        addrs[i].conf.virtual_names = vn;
1101	
1102	        vn->names.hash = addr[i].hash;
1103	        vn->names.wc_head = addr[i].wc_head;
1104	        vn->names.wc_tail = addr[i].wc_tail;
1105	#if (NGX_PCRE)
1106	        vn->nregex = addr[i].nregex;
1107	        vn->regex = addr[i].regex;
1108	#endif
1109	    }
1110	
1111	    return NGX_OK;
1112	}
1113	
1114	
1115	#if (NGX_HAVE_INET6)
1116	
1117	static ngx_int_t
1118	ngx_stream_add_addrs6(ngx_conf_t *cf, ngx_stream_port_t *stport,
1119	    ngx_stream_conf_addr_t *addr)
1120	{
1121	    ngx_uint_t                   i;
1122	    struct sockaddr_in6         *sin6;
1123	    ngx_stream_in6_addr_t       *addrs6;
1124	    ngx_stream_virtual_names_t  *vn;
1125	
1126	    stport->addrs = ngx_pcalloc(cf->pool,
1127	                                stport->naddrs * sizeof(ngx_stream_in6_addr_t));
1128	    if (stport->addrs == NULL) {
1129	        return NGX_ERROR;
1130	    }
1131	
1132	    addrs6 = stport->addrs;
1133	
1134	    for (i = 0; i < stport->naddrs; i++) {
1135	
1136	        sin6 = (struct sockaddr_in6 *) addr[i].opt.sockaddr;
1137	        addrs6[i].addr6 = sin6->sin6_addr;
1138	        addrs6[i].conf.default_server = addr[i].default_server;
1139	#if (NGX_STREAM_SSL)
1140	        addrs6[i].conf.ssl = addr[i].opt.ssl;
1141	#endif
1142	        addrs6[i].conf.proxy_protocol = addr[i].opt.proxy_protocol;
1143	
1144	        if (addr[i].hash.buckets == NULL
1145	            && (addr[i].wc_head == NULL
1146	                || addr[i].wc_head->hash.buckets == NULL)
1147	            && (addr[i].wc_tail == NULL
1148	                || addr[i].wc_tail->hash.buckets == NULL)
1149	#if (NGX_PCRE)
1150	            && addr[i].nregex == 0
1151	#endif
1152	            )
1153	        {
1154	            continue;
1155	        }
1156	
1157	        vn = ngx_palloc(cf->pool, sizeof(ngx_stream_virtual_names_t));
1158	        if (vn == NULL) {
