314	static void
315	ngx_stream_log_session(ngx_stream_session_t *s)
316	{
317	    ngx_uint_t                    i, n;
318	    ngx_stream_handler_pt        *log_handler;
319	    ngx_stream_core_main_conf_t  *cmcf;
320	
321	    cmcf = ngx_stream_get_module_main_conf(s, ngx_stream_core_module);
322	
323	    log_handler = cmcf->phases[NGX_STREAM_LOG_PHASE].handlers.elts;
324	    n = cmcf->phases[NGX_STREAM_LOG_PHASE].handlers.nelts;
325	
326	    for (i = 0; i < n; i++) {
327	        log_handler[i](s);
328	    }
329	}
330	
331	
332	static void
333	ngx_stream_close_connection(ngx_connection_t *c)
334	{
335	    ngx_pool_t  *pool;
336	
337	    ngx_log_debug1(NGX_LOG_DEBUG_STREAM, c->log, 0,
338	                   "close stream connection: %d", c->fd);
339	
340	#if (NGX_STREAM_SSL)
341	
342	    if (c->ssl) {
343	        if (ngx_ssl_shutdown(c) == NGX_AGAIN) {
344	            c->ssl->handler = ngx_stream_close_connection;
345	            return;
346	        }
347	    }
348	
349	#endif
350	
351	#if (NGX_STAT_STUB)
352	    (void) ngx_atomic_fetch_add(ngx_stat_active, -1);
353	#endif
354	
355	    pool = c->pool;
356	
357	    ngx_close_connection(c);
358	
359	    ngx_destroy_pool(pool);
360	}
361	
362	
363	static u_char *
364	ngx_stream_log_error(ngx_log_t *log, u_char *buf, size_t len)
365	{
366	    u_char                *p;
367	    ngx_stream_session_t  *s;
368	
369	    if (log->action) {
370	        p = ngx_snprintf(buf, len, " while %s", log->action);
371	        len -= p - buf;
372	        buf = p;
373	    }
374	
375	    s = log->data;
376	
377	    p = ngx_snprintf(buf, len, ", %sclient: %V, server: %V",
378	                     s->connection->type == SOCK_DGRAM ? "udp " : "",
379	                     &s->connection->addr_text,
380	                     &s->connection->listening->addr_text);
381	    len -= p - buf;
382	    buf = p;
383	
384	    if (s->log_handler) {
385	        p = s->log_handler(log, buf, len);
386	    }
387	
388	    return p;
389	}
