168	void
169	ngx_stream_core_run_phases(ngx_stream_session_t *s)
170	{
171	    ngx_int_t                     rc;
172	    ngx_stream_phase_handler_t   *ph;
173	    ngx_stream_core_main_conf_t  *cmcf;
174	
175	    cmcf = ngx_stream_get_module_main_conf(s, ngx_stream_core_module);
176	
177	    ph = cmcf->phase_engine.handlers;
178	
179	    while (ph[s->phase_handler].checker) {
180	
181	        rc = ph[s->phase_handler].checker(s, &ph[s->phase_handler]);
182	
183	        if (rc == NGX_OK) {
184	            return;
185	        }
186	    }
187	}
188	
189	
190	ngx_int_t
191	ngx_stream_core_generic_phase(ngx_stream_session_t *s,
192	    ngx_stream_phase_handler_t *ph)
193	{
194	    ngx_int_t  rc;
195	
196	    /*
197	     * generic phase checker,
198	     * used by all phases, except for preread and content
199	     */
200	
201	    ngx_log_debug1(NGX_LOG_DEBUG_STREAM, s->connection->log, 0,
202	                   "generic phase: %ui", s->phase_handler);
203	
204	    rc = ph->handler(s);
205	
206	    if (rc == NGX_OK) {
207	        s->phase_handler = ph->next;
208	        return NGX_AGAIN;
209	    }
210	
211	    if (rc == NGX_DECLINED) {
212	        s->phase_handler++;
213	        return NGX_AGAIN;
214	    }
215	
216	    if (rc == NGX_AGAIN || rc == NGX_DONE) {
217	        return NGX_OK;
218	    }
219	
220	    if (rc == NGX_ERROR) {
221	        rc = NGX_STREAM_INTERNAL_SERVER_ERROR;
222	    }
223	
224	    ngx_stream_finalize_session(s, rc);
225	
226	    return NGX_OK;
227	}
228	
229	
230	ngx_int_t
231	ngx_stream_core_preread_phase(ngx_stream_session_t *s,
232	    ngx_stream_phase_handler_t *ph)
233	{
234	    ngx_int_t                    rc;
235	    ngx_connection_t            *c;
236	    ngx_stream_core_srv_conf_t  *cscf;
237	
238	    c = s->connection;
239	
240	    c->log->action = "prereading client data";
241	
242	    cscf = ngx_stream_get_module_srv_conf(s, ngx_stream_core_module);
243	
244	    if (c->read->timedout) {
245	        rc = NGX_STREAM_OK;
246	        goto done;
247	    }
248	
249	    if (!c->read->timer_set) {
250	        rc = ph->handler(s);
251	
252	        if (rc != NGX_AGAIN) {
253	            goto done;
254	        }
255	    }
256	
257	    if (c->buffer == NULL) {
258	        c->buffer = ngx_create_temp_buf(c->pool, cscf->preread_buffer_size);
259	        if (c->buffer == NULL) {
260	            rc = NGX_ERROR;
261	            goto done;
262	        }
263	    }
264	
265	    if (ngx_stream_preread_can_peek(c)) {
266	        rc = ngx_stream_preread_peek(s, ph);
267	
268	    } else {
269	        rc = ngx_stream_preread(s, ph);
270	    }
271	
272	done:
273	
274	    if (rc == NGX_AGAIN) {
275	        if (ngx_handle_read_event(c->read, 0) != NGX_OK) {
276	            ngx_stream_finalize_session(s, NGX_STREAM_INTERNAL_SERVER_ERROR);
277	            return NGX_OK;
278	        }
279	
280	        if (!c->read->timer_set) {
281	            ngx_add_timer(c->read, cscf->preread_timeout);
282	        }
283	
284	        c->read->handler = ngx_stream_session_handler;
285	
286	        return NGX_OK;
287	    }
288	
289	    if (c->read->timer_set) {
290	        ngx_del_timer(c->read);
291	    }
292	
293	    if (rc == NGX_OK) {
294	        s->phase_handler = ph->next;
295	        return NGX_AGAIN;
296	    }
297	
298	    if (rc == NGX_DECLINED) {
299	        s->phase_handler++;
300	        return NGX_AGAIN;
301	    }
302	
303	    if (rc == NGX_DONE) {
304	        return NGX_OK;
305	    }
306	
307	    if (rc == NGX_ERROR) {
308	        rc = NGX_STREAM_INTERNAL_SERVER_ERROR;
309	    }
310	
311	    ngx_stream_finalize_session(s, rc);
312	
313	    return NGX_OK;
314	}
315	
316	
317	static ngx_uint_t
318	ngx_stream_preread_can_peek(ngx_connection_t *c)
319	{
320	#if (NGX_STREAM_SSL)
321	    if (c->ssl) {
322	        return 0;
323	    }
324	#endif
325	
326	    if ((ngx_event_flags & NGX_USE_CLEAR_EVENT) == 0) {
327	        return 0;
328	    }
329	
330	#if (NGX_HAVE_KQUEUE)
331	    if (ngx_event_flags & NGX_USE_KQUEUE_EVENT) {
332	        return 1;
333	    }
334	#endif
335	
336	#if (NGX_HAVE_EPOLLRDHUP)
337	    if ((ngx_event_flags & NGX_USE_EPOLL_EVENT) && ngx_use_epoll_rdhup) {
338	        return 1;
339	    }
340	#endif
341	
342	    return 0;
343	}
344	
345	
346	static ngx_int_t
347	ngx_stream_preread_peek(ngx_stream_session_t *s, ngx_stream_phase_handler_t *ph)
348	{
349	    ssize_t            n;
350	    ngx_int_t          rc;
351	    ngx_err_t          err;
352	    ngx_connection_t  *c;
353	
354	    c = s->connection;
355	
356	    n = recv(c->fd, (char *) c->buffer->last,
357	             c->buffer->end - c->buffer->last, MSG_PEEK);
358	
359	    err = ngx_socket_errno;
360	
361	    ngx_log_debug1(NGX_LOG_DEBUG_STREAM, c->log, 0, "stream recv(): %z", n);
362	
363	    if (n == -1) {
364	        if (err == NGX_EAGAIN) {
365	            c->read->ready = 0;
366	            return NGX_AGAIN;
367	        }
368	
369	        ngx_connection_error(c, err, "recv() failed");
370	        return NGX_STREAM_OK;
371	    }
372	
373	    if (n == 0) {
374	        return NGX_STREAM_OK;
375	    }
376	
377	    c->buffer->last += n;
378	
379	    rc = ph->handler(s);
380	
381	    if (rc != NGX_AGAIN) {
382	        c->buffer->last = c->buffer->pos;
383	        return rc;
384	    }
385	
386	    if (c->buffer->last == c->buffer->end) {
387	        ngx_log_error(NGX_LOG_ERR, c->log, 0, "preread buffer full");
388	        return NGX_STREAM_BAD_REQUEST;
389	    }
390	
391	    if (c->read->pending_eof) {
392	        return NGX_STREAM_OK;
393	    }
394	
395	    c->buffer->last = c->buffer->pos;
396	
397	    return NGX_AGAIN;
398	}
399	
400	
401	static ngx_int_t
402	ngx_stream_preread(ngx_stream_session_t *s, ngx_stream_phase_handler_t *ph)
403	{
404	    ssize_t            n;
405	    ngx_int_t          rc;
406	    ngx_connection_t  *c;
407	
408	    c = s->connection;
409	
410	    while (c->read->ready) {
411	
412	        n = c->recv(c, c->buffer->last, c->buffer->end - c->buffer->last);
413	
414	        if (n == NGX_AGAIN) {
415	            return NGX_AGAIN;
416	        }
417	
418	        if (n == NGX_ERROR || n == 0) {
419	            return NGX_STREAM_OK;
420	        }
421	
422	        c->buffer->last += n;
423	
424	        rc = ph->handler(s);
425	
426	        if (rc != NGX_AGAIN) {
427	            return rc;
428	        }
429	
430	        if (c->buffer->last == c->buffer->end) {
431	            ngx_log_error(NGX_LOG_ERR, c->log, 0, "preread buffer full");
432	            return NGX_STREAM_BAD_REQUEST;
433	        }
434	    }
435	
436	    return NGX_AGAIN;
437	}
