473	
474	ngx_int_t
475	ngx_stream_validate_host(ngx_str_t *host, ngx_pool_t *pool, ngx_uint_t alloc)
476	{
477	    u_char     *h, ch;
478	    size_t      i, dot_pos, host_len;
479	    ngx_int_t   port;
480	
481	    enum {
482	        sw_host_start = 0,
483	        sw_host,
484	        sw_host_ip_literal,
485	        sw_host_end,
486	        sw_port,
487	    } state;
488	
489	    dot_pos = host->len;
490	    host_len = host->len;
491	    port = 0;
492	
493	    h = host->data;
494	
495	    state = sw_host_start;
496	
497	    for (i = 0; i < host->len; i++) {
498	        ch = h[i];
499	
500	        switch (state) {
501	
502	        case sw_host_start:
503	
504	            if (ch == '[') {
505	                state = sw_host_ip_literal;
506	                break;
507	            }
508	
509	            state = sw_host;
510	
511	            /* fall through */
512	
513	        case sw_host:
514	
515	            if (ch >= 'A' && ch <= 'Z') {
516	                alloc = 1;
517	                break;
518	            }
519	
520	            if (ch >= 'a' && ch <= 'z') {
521	                break;
522	            }
523	
524	            if (ch >= '0' && ch <= '9') {
525	                break;
526	            }
527	
528	            switch (ch) {
529	            case ':':
530	                host_len = i;
531	                state = sw_port;
532	                break;
533	            case '-':
534	                break;
535	            case '.':
536	                if (dot_pos == i - 1) {
537	                    return NGX_DECLINED;
538	                }
539	                dot_pos = i;
540	                break;
541	            case '_':
542	            case '~':
543	                /* unreserved */
544	                break;
545	            case '!':
546	            case '$':
547	            case '&':
548	            case '\'':
549	            case '(':
550	            case ')':
551	            case '*':
552	            case '+':
553	            case ',':
554	            case ';':
555	            case '=':
556	                /* sub-delims */
557	                break;
558	            case '%':
559	                /* pct-encoded */
560	                break;
561	            default:
562	                return NGX_DECLINED;
563	            }
564	            break;
565	
566	        case sw_host_ip_literal:
567	
568	            if (ch >= 'A' && ch <= 'Z') {
569	                alloc = 1;
570	                break;
571	            }
572	
573	            if (ch >= 'a' && ch <= 'z') {
574	                break;
575	            }
576	
577	            if (ch >= '0' && ch <= '9') {
578	                break;
579	            }
580	
581	            switch (ch) {
582	            case ':':
583	                break;
584	            case ']':
585	                host_len = i + 1;
586	                state = sw_host_end;
587	                break;
588	            case '-':
589	                break;
590	            case '.':
591	                if (dot_pos == i - 1) {
592	                    return NGX_DECLINED;
593	                }
594	                dot_pos = i;
595	                break;
596	            case '_':
597	            case '~':
598	                /* unreserved */
599	                break;
600	            case '!':
601	            case '$':
602	            case '&':
603	            case '\'':
604	            case '(':
605	            case ')':
606	            case '*':
607	            case '+':
608	            case ',':
609	            case ';':
610	            case '=':
611	                /* sub-delims */
612	                break;
613	            default:
614	                return NGX_DECLINED;
615	            }
616	            break;
617	
618	        case sw_host_end:
619	
620	            if (ch == ':') {
621	                state = sw_port;
622	                break;
623	            }
624	            return NGX_DECLINED;
625	
626	        case sw_port:
627	
628	            if (ch >= '0' && ch <= '9') {
629	                if (port >= 6553 && (port > 6553 || (ch - '0') > 5)) {
630	                    return NGX_DECLINED;
631	                }
632	
633	                port = port * 10 + (ch - '0');
634	                break;
635	            }
636	            return NGX_DECLINED;
637	        }
638	    }
639	
640	    if (state == sw_host_ip_literal) {
641	        return NGX_DECLINED;
642	    }
643	
644	    if (dot_pos == host_len - 1) {
645	        host_len--;
646	    }
647	
648	    if (host_len == 0) {
649	        return NGX_DECLINED;
650	    }
651	
652	    if (alloc) {
653	        host->data = ngx_pnalloc(pool, host_len);
654	        if (host->data == NULL) {
655	            return NGX_ERROR;
656	        }
657	
658	        ngx_strlow(host->data, h, host_len);
659	    }
660	
661	    host->len = host_len;
662	
663	    return NGX_OK;
664	}
