667	ngx_int_t
668	ngx_stream_find_virtual_server(ngx_stream_session_t *s,
669	    ngx_str_t *host, ngx_stream_core_srv_conf_t **cscfp)
670	{
671	    ngx_stream_core_srv_conf_t  *cscf;
672	
673	    if (s->virtual_names == NULL) {
674	        return NGX_DECLINED;
675	    }
676	
677	    cscf = ngx_hash_find_combined(&s->virtual_names->names,
678	                                  ngx_hash_key(host->data, host->len),
679	                                  host->data, host->len);
680	
681	    if (cscf) {
682	        *cscfp = cscf;
683	        return NGX_OK;
684	    }
685	
686	#if (NGX_PCRE)
687	
688	    if (host->len && s->virtual_names->nregex) {
689	        ngx_int_t                  n;
690	        ngx_uint_t                 i;
691	        ngx_stream_server_name_t  *sn;
692	
693	        sn = s->virtual_names->regex;
694	
695	        for (i = 0; i < s->virtual_names->nregex; i++) {
696	
697	            n = ngx_stream_regex_exec(s, sn[i].regex, host);
698	
699	            if (n == NGX_DECLINED) {
700	                continue;
701	            }
702	
703	            if (n == NGX_OK) {
704	                *cscfp = sn[i].server;
705	                return NGX_OK;
706	            }
707	
708	            return NGX_ERROR;
709	        }
710	    }
711	
712	#endif /* NGX_PCRE */
713	
714	    return NGX_DECLINED;
715	}
