815	static char *
816	ngx_stream_core_merge_srv_conf(ngx_conf_t *cf, void *parent, void *child)
817	{
818	    ngx_stream_core_srv_conf_t *prev = parent;
819	    ngx_stream_core_srv_conf_t *conf = child;
820	
821	    ngx_str_t                  name;
822	    ngx_stream_server_name_t  *sn;
823	
824	    ngx_conf_merge_msec_value(conf->resolver_timeout,
825	                              prev->resolver_timeout, 30000);
826	
827	    if (conf->resolver == NULL) {
828	
829	        if (prev->resolver == NULL) {
830	
831	            /*
832	             * create dummy resolver in stream {} context
833	             * to inherit it in all servers
834	             */
835	
836	            prev->resolver = ngx_resolver_create(cf, NULL, 0);
837	            if (prev->resolver == NULL) {
838	                return NGX_CONF_ERROR;
839	            }
840	        }
841	
842	        conf->resolver = prev->resolver;
843	    }
844	
845	    if (conf->error_log == NULL) {
846	        if (prev->error_log) {
847	            conf->error_log = prev->error_log;
848	        } else {
849	            conf->error_log = &cf->cycle->new_log;
850	        }
851	    }
852	
853	    ngx_conf_merge_msec_value(conf->proxy_protocol_timeout,
854	                              prev->proxy_protocol_timeout, 30000);
855	
856	    ngx_conf_merge_value(conf->tcp_nodelay, prev->tcp_nodelay, 1);
857	
858	    ngx_conf_merge_size_value(conf->preread_buffer_size,
859	                              prev->preread_buffer_size, 16384);
860	
861	    ngx_conf_merge_msec_value(conf->preread_timeout,
862	                              prev->preread_timeout, 30000);
863	
864	    if (conf->server_names.nelts == 0) {
865	        /* the array has 4 empty preallocated elements, so push cannot fail */
866	        sn = ngx_array_push(&conf->server_names);
867	#if (NGX_PCRE)
868	        sn->regex = NULL;
869	#endif
870	        sn->server = conf;
871	        ngx_str_set(&sn->name, "");
872	    }
873	
874	    sn = conf->server_names.elts;
875	    name = sn[0].name;
876	
877	#if (NGX_PCRE)
878	    if (sn->regex) {
879	        name.len++;
880	        name.data--;
881	    } else
882	#endif
883	
884	    if (name.data[0] == '.') {
885	        name.len--;
886	        name.data++;
887	    }
888	
889	    conf->server_name.len = name.len;
890	    conf->server_name.data = ngx_pstrdup(cf->pool, &name);
891	    if (conf->server_name.data == NULL) {
892	        return NGX_CONF_ERROR;
893	    }
894	
895	    return NGX_CONF_OK;
896	}
