908	static char *
909	ngx_stream_core_server(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
910	{
911	    char                         *rv;
912	    void                         *mconf;
913	    ngx_uint_t                    m;
914	    ngx_conf_t                    pcf;
915	    ngx_stream_module_t          *module;
916	    ngx_stream_conf_ctx_t        *ctx, *stream_ctx;
917	    ngx_stream_core_srv_conf_t   *cscf, **cscfp;
918	    ngx_stream_core_main_conf_t  *cmcf;
919	
920	    ctx = ngx_pcalloc(cf->pool, sizeof(ngx_stream_conf_ctx_t));
921	    if (ctx == NULL) {
922	        return NGX_CONF_ERROR;
923	    }
924	
925	    stream_ctx = cf->ctx;
926	    ctx->main_conf = stream_ctx->main_conf;
927	
928	    /* the server{}'s srv_conf */
929	
930	    ctx->srv_conf = ngx_pcalloc(cf->pool,
931	                                sizeof(void *) * ngx_stream_max_module);
932	    if (ctx->srv_conf == NULL) {
933	        return NGX_CONF_ERROR;
934	    }
935	
936	    for (m = 0; cf->cycle->modules[m]; m++) {
937	        if (cf->cycle->modules[m]->type != NGX_STREAM_MODULE) {
938	            continue;
939	        }
940	
941	        module = cf->cycle->modules[m]->ctx;
942	
943	        if (module->create_srv_conf) {
944	            mconf = module->create_srv_conf(cf);
945	            if (mconf == NULL) {
946	                return NGX_CONF_ERROR;
947	            }
948	
949	            ctx->srv_conf[cf->cycle->modules[m]->ctx_index] = mconf;
950	        }
951	    }
952	
953	    /* the server configuration context */
954	
955	    cscf = ctx->srv_conf[ngx_stream_core_module.ctx_index];
956	    cscf->ctx = ctx;
957	
958	    cmcf = ctx->main_conf[ngx_stream_core_module.ctx_index];
959	
960	    cscfp = ngx_array_push(&cmcf->servers);
961	    if (cscfp == NULL) {
962	        return NGX_CONF_ERROR;
963	    }
964	
965	    *cscfp = cscf;
966	
967	
968	    /* parse inside server{} */
969	
970	    pcf = *cf;
971	    cf->ctx = ctx;
972	    cf->cmd_type = NGX_STREAM_SRV_CONF;
973	
974	    rv = ngx_conf_parse(cf, NULL);
975	
976	    *cf = pcf;
977	
978	    if (rv == NGX_CONF_OK && !cscf->listen) {
979	        ngx_log_error(NGX_LOG_EMERG, cf->log, 0,
980	                      "no \"listen\" is defined for server in %s:%ui",
981	                      cscf->file_name, cscf->line);
982	        return NGX_CONF_ERROR;
983	    }
984	
985	    return rv;
986	}
