988	
989	static char *
990	ngx_stream_core_listen(ngx_conf_t *cf, ngx_command_t *cmd, void *conf)
991	{
992	    ngx_stream_core_srv_conf_t  *cscf = conf;
993	
994	    ngx_str_t                *value, size;
995	    ngx_url_t                 u;
996	    ngx_uint_t                n, i, backlog;
997	    ngx_stream_listen_opt_t   lsopt;
998	
999	    cscf->listen = 1;
1000	
1001	    value = cf->args->elts;
1002	
1003	    ngx_memzero(&u, sizeof(ngx_url_t));
1004	
1005	    u.url = value[1];
1006	    u.listen = 1;
1007	
1008	    if (ngx_parse_url(cf->pool, &u) != NGX_OK) {
1009	        if (u.err) {
1010	            ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1011	                               "%s in \"%V\" of the \"listen\" directive",
1012	                               u.err, &u.url);
1013	        }
1014	
1015	        return NGX_CONF_ERROR;
1016	    }
1017	
1018	    ngx_memzero(&lsopt, sizeof(ngx_stream_listen_opt_t));
1019	
1020	    lsopt.backlog = NGX_LISTEN_BACKLOG;
1021	    lsopt.type = SOCK_STREAM;
1022	    lsopt.rcvbuf = -1;
1023	    lsopt.sndbuf = -1;
1024	#if (NGX_HAVE_SETFIB)
1025	    lsopt.setfib = -1;
1026	#endif
1027	#if (NGX_HAVE_TCP_FASTOPEN)
1028	    lsopt.fastopen = -1;
1029	#endif
1030	#if (NGX_HAVE_INET6)
1031	    lsopt.ipv6only = 1;
1032	#endif
1033	
1034	    backlog = 0;
1035	
1036	    for (i = 2; i < cf->args->nelts; i++) {
1037	
1038	        if (ngx_strcmp(value[i].data, "default_server") == 0) {
1039	            lsopt.default_server = 1;
1040	            continue;
1041	        }
1042	
1043	#if !(NGX_WIN32)
1044	        if (ngx_strcmp(value[i].data, "udp") == 0) {
1045	            lsopt.type = SOCK_DGRAM;
1046	            continue;
1047	        }
1048	#endif
1049	
1050	        if (ngx_strcmp(value[i].data, "bind") == 0) {
1051	            lsopt.set = 1;
1052	            lsopt.bind = 1;
1053	            continue;
1054	        }
1055	
1056	#if (NGX_HAVE_SETFIB)
1057	        if (ngx_strncmp(value[i].data, "setfib=", 7) == 0) {
1058	            lsopt.setfib = ngx_atoi(value[i].data + 7, value[i].len - 7);
1059	            lsopt.set = 1;
1060	            lsopt.bind = 1;
1061	
1062	            if (lsopt.setfib == NGX_ERROR) {
1063	                ngx_conf_log_error(NGX_LOG_EMERG, cf, 0,
1064	                                   "invalid setfib \"%V\"", &value[i]);
1065	                return NGX_CONF_ERROR;
1066	            }
1067	
1068	            continue;
1069	        }
1070	#endif
1071	
